<?php
namespace App\Http\Controllers\Admin;use App\Http\Controllers\Controller;use App\Models\{Brand,Category,Product};use Illuminate\Http\{RedirectResponse,Request};use Illuminate\Support\Str;use Illuminate\View\View;
class ProductController extends Controller{use HandlesAdminUploads;public function index(Request $r):View{$q=Product::with('category','brandModel');if($r->filled('q'))$q->where('name','like','%'.$r->q.'%');if($r->filled('category_id'))$q->where('category_id',$r->category_id);if($r->filled('brand_id'))$q->where('brand_id',$r->brand_id);if($r->filled('is_active'))$q->where('is_active',$r->is_active);return view('admin.products.index',['products'=>$q->latest()->paginate(15),'categories'=>Category::all(),'brands'=>Brand::all()]);}public function create():View{return view('admin.products.form',['product'=>new Product(['is_active'=>true]),'categories'=>Category::all(),'brands'=>Brand::all()]);}public function store(Request $r):RedirectResponse{$data=$this->data($r);$data['slug']=$data['slug']?:Str::slug($data['name']);$data['image']=$this->upload($r,'image','products');if($r->hasFile('gallery'))$data['gallery']=array_map(fn($f)=>'storage/'.$f->store('products','public'),$r->file('gallery'));Product::create($data);return redirect()->route('admin.products.index')->with('success','محصول ذخیره شد');}public function edit(Product $product):View{return view('admin.products.form',['product'=>$product,'categories'=>Category::all(),'brands'=>Brand::all()]);}public function update(Request $r,Product $product):RedirectResponse{$data=$this->data($r,$product->id);$data['image']=$this->upload($r,'image','products',$product->image);if($r->hasFile('gallery'))$data['gallery']=array_map(fn($f)=>'storage/'.$f->store('products','public'),$r->file('gallery'));$product->update($data);return redirect()->route('admin.products.index')->with('success','محصول به‌روزرسانی شد');}public function destroy(Product $product):RedirectResponse{$product->delete();return back();}private function data(Request $r,$id=null):array{return $r->validate(['category_id'=>'required|exists:categories,id','brand_id'=>'nullable|exists:brands,id','name'=>'required','slug'=>'nullable|unique:products,slug,'.($id??'NULL').',id','image'=>'nullable|image|max:3072','gallery.*'=>'nullable|image|max:3072','short_description'=>'nullable','description'=>'nullable','specifications'=>'nullable','price'=>'required|numeric|min:0','discount_price'=>'nullable|numeric|min:0','stock'=>'required|integer|min:0','sku'=>'nullable','brand'=>'nullable','rating'=>'nullable|numeric','meta_title'=>'nullable','meta_description'=>'nullable'])+['is_featured'=>$r->boolean('is_featured'),'is_new'=>$r->boolean('is_new'),'is_best_selling'=>$r->boolean('is_best_selling'),'is_suggested'=>$r->boolean('is_suggested'),'is_active'=>$r->boolean('is_active')];}}
